using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that scores sentences by word frequency
/// and returns the top-ranked sentences in their original order.
/// </summary>
public partial class ExtractiveSummaryService : IDocumentSummaryService
{
    public string Summarize(string text, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(text))
            return string.Empty;

        var sentences = SplitSentences(text);
        if (sentences.Length <= maxSentences)
            return text.Trim();

        var wordFrequencies = ComputeWordFrequencies(text);
        var scored = sentences
            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index)
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static string[] SplitSentences(string text)
    {
        return SentenceRegex().Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToArray();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(string text)
    {
        var words = WordRegex().Matches(text.ToLowerInvariant());
        var frequencies = new Dictionary<string, int>();
        foreach (Match match in words)
        {
            var word = match.Value;
            if (word.Length <= 2) continue; // skip short words
            frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
        }
        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = WordRegex().Matches(sentence.ToLowerInvariant());
        if (words.Count == 0) return 0;

        double score = 0;
        foreach (Match match in words)
        {
            score += wordFrequencies.GetValueOrDefault(match.Value);
        }
        return score / words.Count;
    }

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Text))
            return BadRequest("Text must not be empty.");

        var summary = _summaryService.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        });
    }
}

